import{_ as a,H as n,f as t,i as e}from"./chunks/framework.BHvCMIhP.js";const g=JSON.parse('{"title":"向量时钟与版本向量","description":"","frontmatter":{},"headers":[],"relativePath":"../distributedLearning/07-向量时钟与版本向量.md","filePath":"../distributedLearning/07-向量时钟与版本向量.md","lastUpdated":1778496697000}'),p={name:"../distributedLearning/07-向量时钟与版本向量.md"};function i(o,s,l,r,c,d){return n(),t("div",null,[...s[0]||(s[0]=[e(`<h1 id="向量时钟与版本向量" tabindex="-1">向量时钟与版本向量 <a class="header-anchor" href="#向量时钟与版本向量" aria-label="Permalink to &quot;向量时钟与版本向量&quot;">​</a></h1><p>上一篇 Lamport 逻辑时钟解决了「<strong>给所有事件打全序</strong>」,但它<strong>只给了一半</strong>——你能根据时间戳判断「A 一定在 B 之前」,<strong>却没法反过来说&quot;A 和 B 是并发的&quot;</strong>。在 Dynamo / Riak / Git / 协同编辑这些场景里,<strong>识别&quot;并发&quot;比排序更重要</strong>——只有先知道&quot;两个写是并发的&quot;,你才知道&quot;该合并还是该让用户挑&quot;。这一篇讲清楚向量时钟(Vector Clock)和版本向量(Version Vector)——<strong>因果追踪的标准答案</strong>,以及它在 Dynamo 系一票工程系统里付出的代价。</p><blockquote><p>一句话先记住:<strong>Lamport 时钟单向——A→B 推出 LC(A) &lt; LC(B),反过来不成立</strong>;<strong>向量时钟双向——能完整识别&quot;因果先后&quot;和&quot;并发&quot;</strong>。<strong>代价是每个节点都要带一个长度为 N 的向量</strong>,N 一大就吃不消。<strong>Dynamo / Riak 在生产证明了它能用,但 sibling 暴增能让你 OOM</strong>——CRDT(19 篇)就是为了治这个病而生。</p></blockquote><hr><h2 id="一、lamport-时钟的死结-不识别并发" tabindex="-1">一、Lamport 时钟的死结:不识别并发 <a class="header-anchor" href="#一、lamport-时钟的死结-不识别并发" aria-label="Permalink to &quot;一、Lamport 时钟的死结:不识别并发&quot;">​</a></h2><p>回顾上一篇:Lamport 逻辑时钟给每个事件一个标量 LC,规则是「本地事件 +1、收消息取 max+1」,<strong>性质</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A happens-before B  ⇒  LC(A) &lt; LC(B)   ✓ (单向)</span></span>
<span class="line"><span>LC(A) &lt; LC(B)       ⇒  A happens-before B   ✗ (反过来不成立)</span></span></code></pre></div><p>举个反例:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>节点 1: ●─────●        (e1 LC=1)  (e3 LC=2)</span></span>
<span class="line"><span>                 ╲</span></span>
<span class="line"><span>                  ╲</span></span>
<span class="line"><span>节点 2: ●─────●    ╲   (e2 LC=1)</span></span>
<span class="line"><span>              ╲    ╲</span></span>
<span class="line"><span>               ╲    ╲</span></span>
<span class="line"><span>节点 3:         ●────●  (e4 LC=2, 收 e3)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>LC(e3) = 2, LC(e2) = 1</span></span>
<span class="line"><span>LC(e2) &lt; LC(e3),但 e2 和 e3 之间没有任何消息往来 —— 它们是**并发的**</span></span></code></pre></div><p><strong>Lamport 时钟看 LC(e2)=1 &lt; LC(e3)=2,会错以为 e2 在 e3 之前</strong>——实际上它们并发。</p><h3 id="_1-1-为什么这个死结要命" tabindex="-1">1.1 为什么这个死结要命 <a class="header-anchor" href="#_1-1-为什么这个死结要命" aria-label="Permalink to &quot;1.1 为什么这个死结要命&quot;">​</a></h3><p>在 Dynamo / Riak 这种<strong>多主无主复制</strong>的系统里,<strong>并发写是常态</strong>:</p><ul><li>用户 U 在客户端 A 写 <code>cart = [book]</code></li><li>同时(几乎)在客户端 B 写 <code>cart = [milk]</code></li><li>两个写都成功,系统里出现两个版本</li></ul><p><strong>这时系统必须知道</strong>:这两个写<strong>是并发的</strong>(不是 A 写完 B 才写),从而<strong>不能直接覆盖</strong>——要么合并(<code>cart = [book, milk]</code>),要么把两个版本都返回给应用层让它解决。</p><p><strong>用 Lamport 时钟做不到</strong>——它只能给出一个数,<strong>无法回答&quot;这两个写有没有因果关系&quot;</strong>。</p><h3 id="_1-2-我们到底想要什么" tabindex="-1">1.2 我们到底想要什么 <a class="header-anchor" href="#_1-2-我们到底想要什么" aria-label="Permalink to &quot;1.2 我们到底想要什么&quot;">​</a></h3><p>我们想要一个时间戳函数 <code>VC(e)</code>,使得:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A happens-before B   ⇔   VC(A) &lt; VC(B)   (严格小于,双向)</span></span>
<span class="line"><span>A 和 B 并发         ⇔   VC(A) 与 VC(B) 既不 ≤ 也不 ≥</span></span></code></pre></div><p><strong>双向</strong>——这是关键。向量时钟就是为此而生。</p><hr><h2 id="二、向量时钟的定义-mattern-1989-fidge-1988" tabindex="-1">二、向量时钟的定义(Mattern 1989 / Fidge 1988) <a class="header-anchor" href="#二、向量时钟的定义-mattern-1989-fidge-1988" aria-label="Permalink to &quot;二、向量时钟的定义(Mattern 1989 / Fidge 1988)&quot;">​</a></h2><h3 id="_2-1-数据结构" tabindex="-1">2.1 数据结构 <a class="header-anchor" href="#_2-1-数据结构" aria-label="Permalink to &quot;2.1 数据结构&quot;">​</a></h3><p><strong>每个节点 i 维护一个长度为 N 的向量</strong> <code>VC_i = [c_1, c_2, ..., c_N]</code>,其中 <code>c_j</code> 表示「节点 i 所知的节点 j 已经发生过多少事件」。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>N = 3 个节点的系统:</span></span>
<span class="line"><span>    节点 1: [0, 0, 0]</span></span>
<span class="line"><span>    节点 2: [0, 0, 0]</span></span>
<span class="line"><span>    节点 3: [0, 0, 0]</span></span></code></pre></div><h3 id="_2-2-三条规则" tabindex="-1">2.2 三条规则 <a class="header-anchor" href="#_2-2-三条规则" aria-label="Permalink to &quot;2.2 三条规则&quot;">​</a></h3><p><strong>规则 1(本地事件)</strong>:节点 i 发生本地事件,自己那一位 +1</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>节点 1 写了一次 → VC_1 = [1, 0, 0]</span></span></code></pre></div><p><strong>规则 2(发送消息)</strong>:节点 i 发消息,先自己 +1,然后把向量随消息发出去</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>节点 1: 本地事件 [1,0,0] → 发消息时再 +1 → [2,0,0] → 消息携带 [2,0,0]</span></span></code></pre></div><p><strong>规则 3(接收消息)</strong>:节点 j 收到消息向量 <code>m</code>,<strong>逐分量取 max</strong>,然后自己那一位 +1</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>节点 2 当前 VC_2 = [0, 1, 0]</span></span>
<span class="line"><span>收到消息向量 m = [2, 0, 0]</span></span>
<span class="line"><span>逐分量 max: [max(0,2), max(1,0), max(0,0)] = [2, 1, 0]</span></span>
<span class="line"><span>节点 2 自己那一位 +1: [2, 2, 0]</span></span></code></pre></div><h3 id="_2-3-一张图看懂" tabindex="-1">2.3 一张图看懂 <a class="header-anchor" href="#_2-3-一张图看懂" aria-label="Permalink to &quot;2.3 一张图看懂&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>节点 1   [1,0,0]●─────────────●[2,0,0]</span></span>
<span class="line"><span>                 ╲                ╲</span></span>
<span class="line"><span>                  ╲                ╲ 发消息 m=[2,0,0]</span></span>
<span class="line"><span>                   ╲                ╲</span></span>
<span class="line"><span>节点 2         [0,1,0]●─────────●─────────●[2,3,0]</span></span>
<span class="line"><span>                       ╲              ╲收到 m, max+1 → [2,2,0]</span></span>
<span class="line"><span>                        ╲ 本地事件      └─ 本地 → [2,3,0]</span></span>
<span class="line"><span>                         ╲</span></span>
<span class="line"><span>节点 3                    ●[0,0,1]──────●[0,0,2]</span></span>
<span class="line"><span>                          本地           本地</span></span></code></pre></div><p><strong>每一根向量都是一个&quot;我所看到的世界状态&quot;</strong>——节点 2 看到 <code>[2,3,0]</code> 意味着:&quot;我知道节点 1 发生过 2 个事件,我自己发生过 3 个,节点 3 我还没听说&quot;。</p><hr><h2 id="三、关系判定-三条比较规则" tabindex="-1">三、关系判定:三条比较规则 <a class="header-anchor" href="#三、关系判定-三条比较规则" aria-label="Permalink to &quot;三、关系判定:三条比较规则&quot;">​</a></h2><p>给定两个向量时钟 <code>VC(A) = [a_1,...,a_n]</code> 和 <code>VC(B) = [b_1,...,b_n]</code>,有三种关系:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. VC(A) &lt; VC(B)</span></span>
<span class="line"><span>   ⇔  对所有 i,a_i ≤ b_i,且至少一个 j 有 a_j &lt; b_j</span></span>
<span class="line"><span>   ⇔  A happens-before B(因果先于)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. VC(A) &gt; VC(B)</span></span>
<span class="line"><span>   ⇔  对所有 i,a_i ≥ b_i,且至少一个 j 有 a_j &gt; b_j</span></span>
<span class="line"><span>   ⇔  B happens-before A</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 既不 ≤ 也不 ≥</span></span>
<span class="line"><span>   ⇔  存在 i 使 a_i &gt; b_i,且存在 j 使 a_j &lt; b_j</span></span>
<span class="line"><span>   ⇔  A 和 B 并发(concurrent)</span></span></code></pre></div><h3 id="_3-1-例子" tabindex="-1">3.1 例子 <a class="header-anchor" href="#_3-1-例子" aria-label="Permalink to &quot;3.1 例子&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>VC(A) = [2, 1, 0]</span></span>
<span class="line"><span>VC(B) = [3, 2, 0]</span></span>
<span class="line"><span>A 每一位 ≤ B,且第 1、2 位严格小于 → A → B (A 先于 B)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>VC(A) = [2, 1, 0]</span></span>
<span class="line"><span>VC(B) = [1, 3, 0]</span></span>
<span class="line"><span>A 第 1 位 &gt; B,A 第 2 位 &lt; B → A 和 B 并发(系统检测到冲突)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>VC(A) = [2, 1, 0]</span></span>
<span class="line"><span>VC(B) = [2, 1, 0]</span></span>
<span class="line"><span>完全相等 → 同一个事件</span></span></code></pre></div><blockquote><p><strong>这一刀是工程的关键</strong>——只有「严格不可比」才叫并发,<strong>Dynamo / Riak 一看见并发就触发 sibling(冲突版本并存)</strong>。</p></blockquote><hr><h2 id="四、向量时钟-vs-版本向量-工程上的-亲兄弟" tabindex="-1">四、向量时钟 vs 版本向量:工程上的&quot;亲兄弟&quot; <a class="header-anchor" href="#四、向量时钟-vs-版本向量-工程上的-亲兄弟" aria-label="Permalink to &quot;四、向量时钟 vs 版本向量:工程上的&quot;亲兄弟&quot;&quot;">​</a></h2><p>学术上两个概念稍有区别,<strong>工程上经常混用</strong>:</p><table tabindex="0"><thead><tr><th>维度</th><th>向量时钟(Vector Clock)</th><th>版本向量(Version Vector)</th></tr></thead><tbody><tr><td>计什么</td><td><strong>所有事件</strong>(本地、收发消息都 +1)</td><td>只计<strong>写操作</strong>(读不 +1)</td></tr><tr><td>用途</td><td>因果追踪(任何事件之间)</td><td>副本数据的版本追踪</td></tr><tr><td>谁提出</td><td>Mattern 1989 / Fidge 1988</td><td>Parker et al. 1983(LOCUS)</td></tr><tr><td>Dynamo 用的是</td><td>名字叫 vector clock,<strong>行为更像 version vector</strong>(只在 put 时 +1)</td><td>—</td></tr></tbody></table><p><strong>结论</strong>:<strong>Dynamo 论文里写&quot;vector clock&quot;但严格说是 version vector</strong>。<strong>工程文档中你看到这两个词,基本可以当同一个东西</strong>——都是「逐分量计数 + 逐分量取 max」的因果追踪机制。</p><hr><h2 id="五、工程映射-1-dynamo-riak-voldemort-的冲突检测" tabindex="-1">五、工程映射 1:Dynamo / Riak / Voldemort 的冲突检测 <a class="header-anchor" href="#五、工程映射-1-dynamo-riak-voldemort-的冲突检测" aria-label="Permalink to &quot;五、工程映射 1:Dynamo / Riak / Voldemort 的冲突检测&quot;">​</a></h2><h3 id="_5-1-dynamo-的写流程" tabindex="-1">5.1 Dynamo 的写流程 <a class="header-anchor" href="#_5-1-dynamo-的写流程" aria-label="Permalink to &quot;5.1 Dynamo 的写流程&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 客户端 PUT(key, value, context)</span></span>
<span class="line"><span>   - context 里带上一次读到的 vector clock(版本号)</span></span>
<span class="line"><span>2. 协调者节点(coordinator)处理写:</span></span>
<span class="line"><span>   - 取自己 node_id 上的计数 +1</span></span>
<span class="line"><span>   - 把新的 vector clock 一起写入,复制到 N 个副本</span></span>
<span class="line"><span>3. 客户端 GET(key)</span></span>
<span class="line"><span>   - 返回 (value, vector_clock) 或多个 sibling 版本</span></span></code></pre></div><p><strong>例</strong>:三个节点 A、B、C,key=<code>cart</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>T0: 初始 cart=&quot;[]&quot;, VC = [A:0, B:0, C:0]</span></span>
<span class="line"><span>T1: 客户端 1 在 A 节点 PUT cart=&quot;[book]&quot;</span></span>
<span class="line"><span>    新 VC = [A:1, B:0, C:0]</span></span>
<span class="line"><span>T2: 网络分区 A | B</span></span>
<span class="line"><span>    客户端 2 在 B 节点 PUT cart=&quot;[milk]&quot;(基于 T0 的版本读到的)</span></span>
<span class="line"><span>    新 VC = [A:0, B:1, C:0]</span></span>
<span class="line"><span>T3: 分区恢复,A 收到 B 的版本</span></span>
<span class="line"><span>    比较 [A:1,B:0,C:0] vs [A:0,B:1,C:0]</span></span>
<span class="line"><span>    → A 第 1 位 &gt; B,A 第 2 位 &lt; B → 并发</span></span>
<span class="line"><span>    → 触发 sibling: 两个值都保留</span></span>
<span class="line"><span>T4: 客户端 GET cart</span></span>
<span class="line"><span>    系统返回:[(&quot;[book]&quot;, VC1), (&quot;[milk]&quot;, VC2)]</span></span>
<span class="line"><span>    应用层负责合并(通常合并为 &quot;[book, milk]&quot;)</span></span></code></pre></div><h3 id="_5-2-riak-的-sibling-资源管理" tabindex="-1">5.2 Riak 的 sibling 资源管理 <a class="header-anchor" href="#_5-2-riak-的-sibling-资源管理" aria-label="Permalink to &quot;5.2 Riak 的 sibling 资源管理&quot;">​</a></h3><p>Riak 把 Dynamo 思路落到生产,<strong>冲突版本叫 sibling</strong>,关键参数:</p><ul><li><code>allow_mult = true</code>:允许保留并发版本(Riak 2.x 默认开)</li><li><code>last_write_wins = true</code>:遇并发用墙钟时间决胜(简单但不安全,可能丢数据)</li></ul><p><strong>应用层负责合并逻辑</strong>——比如购物车合并(集合并集)、计数器(求和,但要小心)、地址簿(用户挑)。</p><h3 id="_5-3-voldemort-linkedin" tabindex="-1">5.3 Voldemort(LinkedIn) <a class="header-anchor" href="#_5-3-voldemort-linkedin" aria-label="Permalink to &quot;5.3 Voldemort(LinkedIn)&quot;">​</a></h3><p>跟 Dynamo 几乎一模一样的玩法,LinkedIn 内部用,<strong>主要存社交关系数据</strong>——合并语义天然友好(关系列表合并)。</p><hr><h2 id="六、工程映射-2-git-的-dag-是隐式向量时钟" tabindex="-1">六、工程映射 2:Git 的 DAG 是隐式向量时钟 <a class="header-anchor" href="#六、工程映射-2-git-的-dag-是隐式向量时钟" aria-label="Permalink to &quot;六、工程映射 2:Git 的 DAG 是隐式向量时钟&quot;">​</a></h2><p>Git 没有显式的&quot;向量时钟&quot;,但 <strong>commit DAG 本质上就是一个因果图</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>            C1 ─── C2 ─── C3 (main)</span></span>
<span class="line"><span>              ╲</span></span>
<span class="line"><span>               ╲</span></span>
<span class="line"><span>                C4 ─── C5 (feature)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>C3 和 C5 并发(没有任何祖先关系直接相连)→ 合并时可能冲突</span></span></code></pre></div><p><strong>Git 用&quot;父 commit hash&quot;代替向量时钟</strong>——每个 commit 都指向它的父 commit,<strong>祖先关系</strong>就是因果关系。<strong>Merge 时 Git 找 LCA(最近公共祖先)</strong>,这个过程<strong>等价于「检测两个 commit 的向量时钟是否并发」</strong>。</p><p><strong>Mercurial 用的更直接</strong>——内部就叫 &quot;changeset DAG&quot;,每个节点有 parent revisions 列表,<strong>这就是向量时钟的退化版</strong>。</p><hr><h2 id="七、工程映射-3-yjs-automerge-协同编辑的因果基础" tabindex="-1">七、工程映射 3:Yjs / Automerge / 协同编辑的因果基础 <a class="header-anchor" href="#七、工程映射-3-yjs-automerge-协同编辑的因果基础" aria-label="Permalink to &quot;七、工程映射 3:Yjs / Automerge / 协同编辑的因果基础&quot;">​</a></h2><p>CRDT 协同编辑(详见 19 篇)对每个编辑操作打<strong>因果时间戳</strong>,确保:</p><ul><li>删除一个字符 → 必须知道这个字符是哪个版本插入的</li><li>撤销一个操作 → 撤销的&quot;对象&quot;必须有清晰因果链</li></ul><p><strong>Yjs / Automerge 内部都维护版本向量</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Yjs 的 state vector:</span></span>
<span class="line"><span>    { client_1: 42, client_2: 17, client_3: 31 }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>意思:我已经看到了 client_1 的第 42 个操作、client_2 的第 17 个、client_3 的第 31 个</span></span>
<span class="line"><span></span></span>
<span class="line"><span>同步时只传&quot;我没看到的&quot;——A 给 B 发 sync 时,B 只回 B 知道但 A 不知道的操作</span></span></code></pre></div><p><strong>这本质上是向量时钟在 CRDT 上的工程化</strong>——把版本向量当<strong>协议层的同步原语</strong>用。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A 的 SV: { c1:42, c2:17, c3:31 }</span></span>
<span class="line"><span>B 的 SV: { c1:45, c2:17, c3:31 }</span></span>
<span class="line"><span>B 看到 A 缺 c1 的 43-45 → 把这三个操作发给 A</span></span></code></pre></div><p><strong>没有这一层,协同编辑无法&quot;按因果顺序应用操作&quot;</strong>——最后文档会乱。</p><hr><h2 id="八、向量时钟的代价" tabindex="-1">八、向量时钟的代价 <a class="header-anchor" href="#八、向量时钟的代价" aria-label="Permalink to &quot;八、向量时钟的代价&quot;">​</a></h2><h3 id="_8-1-向量长度-节点数-o-n" tabindex="-1">8.1 向量长度 = 节点数 = O(N) <a class="header-anchor" href="#_8-1-向量长度-节点数-o-n" aria-label="Permalink to &quot;8.1 向量长度 = 节点数 = O(N)&quot;">​</a></h3><p>这是最大的痛——<strong>100 个节点,每条数据带 100 个数字的元数据</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>key=&quot;cart&quot;</span></span>
<span class="line"><span>value=&quot;[book, milk]&quot;</span></span>
<span class="line"><span>vector_clock = {</span></span>
<span class="line"><span>  &quot;node_1&quot;: 234,  &quot;node_2&quot;: 567,  &quot;node_3&quot;: 12, ...</span></span>
<span class="line"><span>  &quot;node_100&quot;: 89  # 总共 100 个</span></span>
<span class="line"><span>}</span></span></code></pre></div><p><strong>实际开销</strong>:每个数字 8 字节,100 节点 → 800 字节 / 条数据。<strong>比 value 本身还大</strong>。Dynamo 论文也承认这是个问题。</p><h3 id="_8-2-客户端必须带版本号" tabindex="-1">8.2 客户端必须带版本号 <a class="header-anchor" href="#_8-2-客户端必须带版本号" aria-label="Permalink to &quot;8.2 客户端必须带版本号&quot;">​</a></h3><p>GET 之后客户端拿到 <code>(value, vector_clock)</code>,<strong>PUT 必须把 vector_clock 一起回传</strong>——否则系统不知道你&quot;基于哪个版本写的&quot;,会和&quot;全新的写&quot;混淆。</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 错误写法(忽略 vector_clock)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">value, _ </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> client.get(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;cart&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">value.append(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;milk&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">client.put(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;cart&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, value)   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ← 系统不知道这是基于哪个版本</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 正确写法(带回 context)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">value, vc </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> client.get(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;cart&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">value.append(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;milk&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">client.put(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;cart&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, value, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">context</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">vc)  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ← Dynamo 才能正确判因果</span></span></code></pre></div><p><strong>应用层很容易忘</strong>——Riak / Dynamo SDK 都用 <code>context</code> 对象隐藏这一层,但概念上必须懂。</p><h3 id="_8-3-gc-问题-向量永远不会缩" tabindex="-1">8.3 GC 问题:向量永远不会缩 <a class="header-anchor" href="#_8-3-gc-问题-向量永远不会缩" aria-label="Permalink to &quot;8.3 GC 问题:向量永远不会缩&quot;">​</a></h3><p>节点 1 早就退役了,但所有数据上还带着 <code>node_1: xxx</code> 这一位——<strong>向量永远不会变短</strong>,只会越来越长。</p><p><strong>对策</strong>:</p><ul><li><strong>Dotted Version Vectors</strong>(Almeida et al. 2014):用 (node, counter) 对的集合,只保留必要的因果信息,可以缩</li><li><strong>TTL 老数据</strong>:周期性扫库,把陈旧的向量条目清理掉</li><li><strong>Pruning 阈值</strong>:超过 K 个节点的位就合并(代价:丢失部分并发检测精度)</li></ul><h3 id="_8-4-sibling-爆炸-真实事故" tabindex="-1">8.4 sibling 爆炸(真实事故) <a class="header-anchor" href="#_8-4-sibling-爆炸-真实事故" aria-label="Permalink to &quot;8.4 sibling 爆炸(真实事故)&quot;">​</a></h3><p><strong>Jepsen 测试 Riak 时发现的灾难场景</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 应用层不合并 sibling,只是把它们当成&quot;多版本读&quot;</span></span>
<span class="line"><span>2. 每次写都基于&quot;最老的版本&quot;,新写就和老版本并发</span></span>
<span class="line"><span>3. sibling 数量 N → N+1 → N+2 → ... 单 key 数百个 sibling</span></span>
<span class="line"><span>4. 单条记录元数据膨胀到 MB 级</span></span>
<span class="line"><span>5. 内存爆,Riak OOM</span></span></code></pre></div><p><strong>Jepsen 报告</strong>:Riak 在某些工作负载下<strong>单 key 可以累积上万个 sibling</strong>——这是 vector clock 工程的最暗黑面。</p><p><strong>对策</strong>:<strong>应用层必须实现 merge</strong>——读到多个版本时立即合并,写回单一版本。</p><hr><h2 id="九、向量时钟-vs-lamport-vs-hlc-一张表" tabindex="-1">九、向量时钟 vs Lamport vs HLC 一张表 <a class="header-anchor" href="#九、向量时钟-vs-lamport-vs-hlc-一张表" aria-label="Permalink to &quot;九、向量时钟 vs Lamport vs HLC 一张表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>Lamport 标量时钟</th><th>向量时钟</th><th>HLC(下篇)</th></tr></thead><tbody><tr><td>数据结构</td><td>单个数</td><td>长度 N 的向量</td><td>(物理时间, 逻辑位)</td></tr><tr><td>因果判定</td><td>单向(只能排除非因果)</td><td><strong>双向</strong>(能识别并发)</td><td>双向但近似</td></tr><tr><td>元数据开销</td><td>O(1)</td><td>O(N)</td><td>O(1)</td></tr><tr><td>用途</td><td>全序排序</td><td>并发检测</td><td>给事务打外部一致 timestamp</td></tr><tr><td>典型系统</td><td>早期 Lamport 论文</td><td>Dynamo / Riak / Git</td><td>CockroachDB / YugabyteDB</td></tr></tbody></table><p><strong>记忆口诀</strong>:<strong>Lamport 一根数,向量是数组,HLC 物理+逻辑两个数</strong>——一根数省空间但漏并发,数组完整但贵,HLC 折中。</p><hr><h2 id="十、踩坑提醒" tabindex="-1">十、踩坑提醒 <a class="header-anchor" href="#十、踩坑提醒" aria-label="Permalink to &quot;十、踩坑提醒&quot;">​</a></h2><ol><li><strong>以为 Lamport 时钟就够了</strong>——它不识别并发,<strong>Dynamo 系统必须用向量时钟</strong>。把 Lamport 套到多主复制上,会把&quot;并发写&quot;误判成&quot;顺序写&quot;,<strong>直接丢数据</strong>。</li><li><strong>客户端 PUT 不带 context</strong>——Dynamo / Riak 必须回传上次读的 vector clock,<strong>否则每次写都被当&quot;全新写&quot;</strong>,sibling 满天飞。</li><li><strong>不实现 sibling merge</strong>——Jepsen 验证过的 Riak OOM 路径,<strong>业务必须有 merge 函数</strong>(集合并集、计数求和、用户挑)。</li><li><strong>用 last-write-wins 决胜</strong>——<code>last_write_wins = true</code> 看起来省心,但<strong>墙钟不可信</strong>(05 篇),会丢数据。<strong>金融、订单这种宁可应用层合并</strong>。</li><li><strong>节点 ID 用 IP 或主机名</strong>——重启换 IP 就变新节点,向量永远膨胀。<strong>用稳定 UUID + 持久化</strong>。</li><li><strong>向量不做 GC</strong>——退役节点的位永久占着位置,<strong>几年后单条记录元数据几 KB</strong>。要做 Pruning 或换 Dotted Version Vector。</li><li><strong>跨数据中心节点都进同一个向量</strong>——N 跨到几千节点,向量就废了。**分层(per-DC vector + global merge)**才能撑住。</li><li><strong>以为 Git merge 是&quot;按时间合并&quot;</strong>——Git 是按 DAG 合并,<strong>冲突判定就是&quot;向量时钟并发&quot;</strong>;搞错这点写出来的同步工具会丢提交。</li><li><strong>CRDT 不带向量时钟</strong>——CRDT 的 join 满足交换/幂等,**但你怎么知道&quot;对端已经看到哪些操作了&quot;?**那就是版本向量的活,缺了它同步效率为 0。</li><li><strong>指望向量时钟解决&quot;语义冲突&quot;</strong>——它只解决&quot;是否并发&quot;。<strong>两个并发写到底该 union 还是 last-write-wins 还是让用户挑,业务自己定</strong>。向量时钟只是给你「冲突检测」的工具,不是「冲突解决」的工具。</li></ol><hr><p>下一篇 <code>08-HLC 与 TrueTime</code>:向量时钟解决了&quot;识别并发&quot;,但 N 节点 O(N) 的开销让它在跨地域大集群里吃不消。<strong>HLC(混合逻辑时钟)用「物理时间 + 一个小逻辑位」把两者捏到一起</strong>——CockroachDB / YugabyteDB 全靠它撑事务;<strong>Spanner 直接砸钱上 GPS+原子钟,把时间不确定性压到 7ms 以内</strong>,这就是「TrueTime」的工程奇迹——下一篇拆穿它怎么做的。</p>`,101)])])}const u=a(p,[["render",i]]);export{g as __pageData,u as default};
